from flask import Flask, request
from prometheus_client import start_http_server, Counter
import random

app = Flask(__name__)
start_http_server(8001)

requests_total = {}
labels = ['user_id', 'session_id']

@app.before_request
def track_request():
    user_path = request.path
    for label in labels:
        if label in request.headers:
            user_path += f'_{label}_{request.headers[label]}'
    
    if user_path not in requests_total:
        requests_total[user_path] = Counter('http_requests_total', 'Total HTTP Requests', ['endpoint'])
        
    requests_total[user_path].labels(endpoint=user_path).inc()

@app.route('/')
def hello():
    return "Hello, World!"

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8000)